SELECT [20060214-PrezziVenditaBambino].[Model Item No_] AS Article, [20060214-PrezziVenditaBambino].[Item].Description AS Descr, [20060214-PrezziVenditaBambino].[Trademark Code] AS TrademarkCode, [20060214-PrezziVenditaBambino].[Line Code] AS LineCode, [20060214-PrezziVenditaBambino].[Product Family] AS ProductFamily, [20060214-PrezziVenditaBambino].[Product Sex] AS ProductSex, [20060214-PrezziVenditaBambino].[Variable Group 02] AS SizeGroup, [20060214-PrezziVenditaBambino].[Variable Group 01] AS ColorGroup, [20060214-PrezziVenditaBambino].[Variable Code 01] AS Color, [20060214-PrezziVenditaBambino].[Variable Code].Description AS ColorDescr, [20060214-PrezziVenditaBambino].SizeRange, [20060214PrezziAcquistoBambino].PurchPrice, [20060214-PrezziVenditaBambino].SalesPrice
FROM 20060214PrezziAcquistoBambino RIGHT JOIN [20060214-PrezziVenditaBambino] ON ([20060214PrezziAcquistoBambino].[Variable Code 01] = [20060214-PrezziVenditaBambino].[Variable Code 01]) AND ([20060214PrezziAcquistoBambino].SizeRange = [20060214-PrezziVenditaBambino].SizeRange) AND ([20060214PrezziAcquistoBambino].[Model Item No_] = [20060214-PrezziVenditaBambino].[Model Item No_])
WHERE ((([20060214PrezziAcquistoBambino].[Model Item No_]) Is Null));

